const fs = require('fs');
const https = require('https');

async function poll() {
  const apiKey = process.env.PREMBLY_API_KEY || '';
  const url = 'https://api.prembly.com/api/v1/checker-widget/sdk/sessions/';

  try {
    const response = await fetch(url, {
      method: 'GET',
      headers: {
        'x-api-key': apiKey,
        'Content-Type': 'application/json'
      }
    });

    const json = await response.json();

    let count = 0;
    if (Array.isArray(json)) {
        count = json.length;
    } else if (json.data && Array.isArray(json.data)) {
        count = json.data.length;
    } else if (json.data && json.data.data && Array.isArray(json.data.data)) {
        count = json.data.data.length;
    } else if (json.data && typeof json.data.total === 'number') {
        count = json.data.total;
    } else if (typeof json.total === 'number') {
        count = json.total;
    } else {
        count = Object.keys(json).length;
    }

    fs.writeFileSync('/home/user/app/output.log', `Total sessions: ${count}\n`);
    console.log(`Successfully wrote ${count} sessions to output.log`);
  } catch (error) {
    console.error('Error fetching sessions:', error);
    fs.writeFileSync('/home/user/app/output.log', `Error: ${error.message}\n`);
  }
}

poll();

